#!/usr/bin/env python3
# Piece 1c-costv2 (dream-os) — cache-aware cost (ported from dreamai models.ts).
#
# The old calculateCost billed ALL input at full price — blind to prompt caching.
# So the per-turn rupee figure was wrong: cache-read tokens (which bill at 0.1x)
# were priced at 1x, over-reporting cost. (And it surfaced the Haiku 2048-token
# cache MINIMUM: blocks under 2048 silently no-op — Kriya's ~1.4k soul block was
# never actually caching; only her ~3.7k tool bench was.)
#
# Fix (faithful port of dreamai calcCostInr + loop.ts bucket capture):
#   * models.js  — calculateCost takes 5 args: fresh input, output, cache_read,
#                  cache_write; prices read at 0.1x, write at 1.25x.
#   * kriyaTurn  — captures resp.usage.cache_read_input_tokens /
#                  cache_creation_input_tokens, carries them up.
#   * myraLoop   — captures her own + folds Kriya's, prices with all four buckets,
#                  exposes cacheRead/cacheWrite in the return.
#   * chat.js    — done beat now shows cache_read / cache_write so cost is VISIBLE.
#
# Now the rupee figure is correct AND you can see the cache working (or not).

import base64, os, sys
ROOT=os.getcwd()
PAYLOADS={
    'src/agent/models.js': '',
    'src/agent/kriyaTurn.js': '',
    'src/agent/myraLoop.js': '',
}
DONE_OLD = """      if (result.outputTokens != null) donePayload.output_tokens = result.outputTokens;"""
DONE_NEW = """      if (result.outputTokens != null) donePayload.output_tokens = result.outputTokens;
      if (result.cacheRead  != null) donePayload.cache_read  = result.cacheRead;
      if (result.cacheWrite != null) donePayload.cache_write = result.cacheWrite;"""

def main():
    if not os.path.isdir(os.path.join(ROOT,"src","agent")):
        print("ERROR: run from dream-os repo root."); sys.exit(1)
    for rel,b64 in PAYLOADS.items():
        open(os.path.join(ROOT,rel),"wb").write(base64.b64decode(b64)); print(f"OK: overwrote {rel}")
    cp=os.path.join(ROOT,"src","api","vendor","chat.js")
    s=open(cp,encoding="utf-8").read()
    if "donePayload.cache_read" in s:
        print("SKIP: chat.js done beat already carries cache buckets.")
    elif DONE_OLD in s:
        open(cp,"w",encoding="utf-8").write(s.replace(DONE_OLD,DONE_NEW,1))
        print("OK: chat.js done beat now shows cache_read / cache_write.")
    else:
        print("SKIP: done-beat anchor not found — add cache_read/cache_write to donePayload by hand.")
    print("\nPiece 1c-costv2 written. Cost is now cache-aware and the breakdown is visible.")
if __name__=="__main__": main()
